def title_case(s: str) -> str:
    """
    Returns a string in title case where specific small words are kept lowercase,
    unless they are the first or last word of the string.
    """
    if not isinstance(s, str):
        raise TypeError("Input must be a string.")

    if not s:
        return s

    small_words = {
        "a", "an", "and", "as", "at", "but", "by", "for", 
        "in", "nor", "of", "on", "or", "the", "to", "vs"
    }

    words = s.split(' ')
    n = len(words)
    result = []

    for i, word in enumerate(words):
        # First and last words are always capitalized
        if i == 0 or i == n - 1:
            result.append(word.capitalize())
        # Small words in the middle are kept lowercase
        elif word.lower() in small_words:
            result.append(word.lower())
        # All other words are capitalized
        else:
            result.append(word.capitalize())

    return ' '.join(result)
