from typing import Set

def title_case(s: str) -> str:
    """
    Converts a string to title case, keeping specific small words lowercase
    unless they appear at the start or end of the string.
    """
    if not isinstance(s, str):
        raise TypeError("Input must be a string.")

    if not s:
        return s

    small_words: Set[str] = {
        "a", "an", "and", "as", "at", "but", "by", "for", 
        "in", "nor", "of", "on", "or", "the", "to", "vs"
    }

    words = s.split(" ")
    result = []

    for i, word in enumerate(words):
        # Handle empty strings resulting from multiple spaces if necessary,
        # though the prompt specifies words are separated by single spaces.
        if not word:
            result.append("")
            continue

        lower_word = word.lower()

        # Capitalize if it's the first word, last word, or not in the small_words set
        if i == 0 or i == len(words) - 1 or lower_word not in small_words:
            result.append(lower_word.capitalize())
        else:
            result.append(lower_word)

    return " ".join(result)
