from typing import Callable, Iterable, Iterator, TypeVar

T = TypeVar("T")

def take_while(predicate: Callable[[T], bool], iterable: Iterable[T]) -> Iterator[T]:
    """
    Yield items from the iterable as long as the predicate is true.

    Stops immediately upon the first item that fails the predicate, 
    ensuring no subsequent elements are consumed from the iterator.
    """
    if not callable(predicate):
        raise TypeError("predicate must be a callable")

    try:
        iterator = iter(iterable)
    except TypeError as e:
        raise TypeError("iterable must be an iterable object") from e

    for item in iterator:
        if predicate(item):
            yield item
        else:
            break
