import bisect
from typing import List

def lis_length(nums: List[int]) -> int:
    """
    Calculates the length of the longest strictly increasing subsequence of a list.

    Utilizes the Patience Sorting algorithm (binary search approach) to achieve 
    O(n log n) time complexity and O(n) space complexity.
    """
    if not isinstance(nums, list):
        raise TypeError("The input 'nums' must be a list of integers.")

    if not nums:
        return 0

    # tails[i] will store the smallest tail of all increasing subsequences of length i+1
    tails: List[int] = []

    for x in nums:
        if not isinstance(x, int):
            raise TypeError("All elements in the list must be integers.")

        # Binary search for the insertion point to maintain strictly increasing order
        idx = bisect.bisect_left(tails, x)

        if idx < len(tails):
            tails[idx] = x
        else:
            tails.append(x)

    return len(tails)
