from typing import List

def compress_ranges(nums: List[int]) -> str:
    """
    Compresses a list of integers into a comma-separated string of sorted distinct values,
    where runs of 3 or more consecutive integers are represented as 'start-end'.
    """
    if not isinstance(nums, list):
        raise TypeError("The nums argument must be a list.")

    # Extract sorted unique values and validate they are all integers
    try:
        sorted_nums = sorted(set(nums))
    except TypeError as e:
        raise TypeError("All elements in the list must be integers.") from e

    # Explicitly check for non-int types because set() might allow mixed types if they are comparable
    for x in sorted_nums:
        if not isinstance(x, int):
            raise TypeError("All elements in the list must be integers.")

    if not sorted_nums:
        return ""

    result = []
    n = len(sorted_nums)
    i = 0

    while i < n:
        start_idx = i
        # Find the end of the consecutive run
        while i + 1 < n and sorted_nums[i + 1] == sorted_nums[i] + 1:
            i += 1

        run_length = i - start_idx + 1
        if run_length >= 3:
            # Compress runs of 3 or more
            result.append(f"{sorted_nums[start_idx]}-{sorted_nums[i]}")
        else:
            # List individual values for runs of 1 or 2
            for j in range(start_idx, i + 1):
                result.append(str(sorted_nums[j]))

        i += 1

    return ", ".join(result)
