from collections import Counter

def find_anagram_indices(text: str, pattern: str) -> list[int]:
    """
    Finds all starting indices in text where the substring is an anagram of pattern.
    Runs in O(N) time where N is the length of text.
    """
    if not pattern or len(pattern) > len(text):
        return []

    pattern_len = len(pattern)
    text_len = len(text)

    pattern_counts = Counter(pattern)
    window_counts = Counter(text[:pattern_len])

    results = []

    # We track the number of characters that have the exact required frequency
    # to avoid comparing the full dictionaries in each iteration.
    matches = 0
    for char in pattern_counts:
        if window_counts[char] == pattern_counts[char]:
            matches += 1

    # Check the first window
    if matches == len(pattern_counts):
        results.append(0)

    for i in range(1, text_len - pattern_len + 1):
        # Character entering the window
        char_in = text[i + pattern_len - 1]
        # Character leaving the window
        char_out = text[i - 1]

        if char_in == char_out:
            if matches == len(pattern_counts):
                results.append(i)
            continue

        # Update for char_out
        if char_out in pattern_counts:
            if window_counts[char_out] == pattern_counts[char_out]:
                matches -= 1
            window_counts[char_out] -= 1
            if window_counts[char_out] == pattern_counts[char_out]:
                matches += 1

        # Update for char_in
        if char_in in pattern_counts:
            if window_counts[char_in] == pattern_counts[char_in]:
                matches -= 1
            window_counts[char_in] += 1
            if window_counts[char_in] == pattern_counts[char_in]:
                matches += 1

        if matches == len(pattern_counts):
            results.append(i)

    return results
