import re
from typing import List, Tuple

def evaluate(expr: str) -> float:
    """
    Evaluates a string arithmetic expression with support for +, -, *, /, 
    parentheses, and unary operators. Returns the result as a float.

    Args:
        expr: The arithmetic expression string to evaluate.

    Returns:
        The result of the evaluation as a float.

    Raises:
        ValueError: If the expression is malformed or contains invalid characters.
    """
    if not isinstance(expr, str):
        raise ValueError("Expression must be a string.")

    # Tokenize the input string
    # Pattern matches: floating point numbers, integers, and single-character operators/parens
    token_pattern = re.compile(r"\s*(\d*\.\d+|\d+\.\d*|\d+|[+\-*/()])\s*")
    tokens: List[str] = []
    last_end = 0
    for match in token_pattern.finditer(expr):
        if match.start() != last_end:
            raise ValueError(f"Invalid character at index {last_end}")
        tokens.append(match.group(1))
        last_end = match.end()

    if last_end != len(expr) and expr[last_end:].strip():
        raise ValueError(f"Invalid character at index {last_end}")

    pos = 0

    def peek() -> str:
        nonlocal pos
        return tokens[pos] if pos < len(tokens) else ""

    def consume(expected: str = None) -> str:
        nonlocal pos
        if pos >= len(tokens):
            raise ValueError("Unexpected end of expression")
        token = tokens[pos]
        if expected and token != expected:
            raise ValueError(f"Expected {expected}, got {token}")
        pos += 1
        return token

    def parse_primary() -> float:
        """Handles numbers and parenthesized expressions."""
        token = peek()
        if token == '(':
            consume('(')
            result = parse_expression()
            consume(')')
            return result

        if token and (token[0].isdigit() or token[0] == '.'):
            try:
                return float(consume())
            except ValueError:
                raise ValueError(f"Invalid numeric literal: {token}")

        raise ValueError(f"Unexpected token: {token if token else 'EOF'}")

    def parse_unary() -> float:
        """Handles unary + and -."""
        token = peek()
        if token == '+':
            consume('+')
            return parse_unary()
        if token == '-':
            consume('-')
            return -parse_unary()
        return parse_primary()

    def parse_term() -> float:
        """Handles multiplication and division (higher precedence)."""
        result = parse_unary()
        while peek() in ('*', '/'):
            op = consume()
            right = parse_unary()
            if op == '*':
                result *= right
            else:
                if right == 0:
                    raise ValueError("Division by zero")
                result /= right
        return result

    def parse_expression() -> float:
        """Handles addition and subtraction (lower precedence)."""
        result = parse_term()
        while peek() in ('+', '-'):
            op = consume()
            right = parse_term()
            if op == '+':
                result += right
            else:
                result -= right
        return result

    if not tokens:
        raise ValueError("Empty expression")

    try:
        final_result = parse_expression()
    except IndexError:
        raise ValueError("Malformed expression")

    if pos < len(tokens):
        raise ValueError(f"Unexpected trailing token: {tokens[pos]}")

    return float(final_result)
