import re
from collections import deque
from typing import List, Union

def evaluate(expr: str) -> float:
    """
    Evaluates a mathematical expression string with support for +, -, *, /, 
    parentheses, and unary operators. Returns the result as a float.

    Args:
        expr: The arithmetic expression to evaluate.

    Returns:
        The result of the evaluation as a float.

    Raises:
        ValueError: If the expression is malformed or contains invalid characters.
    """
    if not isinstance(expr, str):
        raise ValueError("Expression must be a string.")

    # Tokenize: numbers (including decimals), operators, and parentheses
    token_pattern = re.compile(r"\s*(\d*\.?\d+|[+\-*/()])\s*")
    tokens = token_pattern.findall(expr)

    # Validate that the reconstructed tokens match the original string (ignoring whitespace)
    if "".join(tokens) != "".join(expr.split()):
        raise ValueError("Expression contains invalid characters.")

    # Shunting-yard algorithm to convert infix to postfix
    precedence = {'+': 1, '-': 1, '*': 2, '/': 2}
    output_queue: List[Union[float, str]] = []
    operator_stack: List[str] = []

    # Track if the next token is in a position where a unary operator is possible
    can_be_unary = True

    for token in tokens:
        if token.replace('.', '', 1).isdigit():
            try:
                output_queue.append(float(token))
            except ValueError:
                raise ValueError(f"Invalid number format: {token}")
            can_be_unary = False
        elif token == '(':
            operator_stack.append(token)
            can_be_unary = True
        elif token == ')':
            while operator_stack and operator_stack[-1] != '(':
                output_queue.append(operator_stack.pop())
            if not operator_stack:
                raise ValueError("Mismatched parentheses: missing '('")
            operator_stack.pop()  # Remove '('
            can_be_unary = False
        else:  # Operators
            if can_be_unary:
                # Handle unary minus/plus by transforming to 0 - x or 0 + x
                # We use a special marker 'u' for unary minus or just push 0.0
                if token == '-':
                    output_queue.append(0.0)
                    operator_stack.append('-')
                elif token == '+':
                    pass # Unary plus is identity, can be ignored
                else:
                    raise ValueError(f"Invalid unary operator: {token}")
            else:
                while (operator_stack and operator_stack[-1] != '(' and 
                       precedence.get(operator_stack[-1], 0) >= precedence[token]):
                    output_queue.append(operator_stack.pop())
                operator_stack.append(token)
            can_be_unary = True

    while operator_stack:
        op = operator_stack.pop()
        if op == '(':
            raise ValueError("Mismatched parentheses: missing ')'")
        output_queue.append(op)

    # Postfix evaluation
    eval_stack: List[float] = []
    for token in output_queue:
        if isinstance(token, float):
            eval_stack.append(token)
        else:
            if len(eval_stack) < 2:
                raise ValueError("Malformed expression: insufficient operands.")
            b = eval_stack.pop()
            a = eval_stack.pop()
            if token == '+': eval_stack.append(a + b)
            elif token == '-': eval_stack.append(a - b)
            elif token == '*': eval_stack.append(a * b)
            elif token == '/':
                if b == 0:
                    raise ValueError("Division by zero.")
                eval_stack.append(a / b)

    if len(eval_stack) != 1:
        raise ValueError("Malformed expression: too many operands.")

    return float(eval_stack[0])
